{
  "$schema" : "https://json-schema.org/draft/2020-12/schema",
  "type" : "object",
  "properties" : {
    "edgeList" : {
      "description" : "Edge connection list (required). Each edge.source/edge.target must reference existing node.id",
      "type" : "array",
      "items" : {
        "type" : "object",
        "properties" : {
          "config" : {
            "type" : "string",
            "description" : "Edge business config as JSON string (optional). If omitted, default routing behavior is used"
          },
          "edgeId" : {
            "type" : "string",
            "description" : "Edge ID (optional), unique identifier within the canvas, e.g., edge_001"
          },
          "source" : {
            "type" : "string",
            "description" : "Upstream node ID (required), must match an existing node.id"
          },
          "sourceBranchId" : {
            "type" : "string",
            "description" : "Upstream branch ID (optional). Use when source node is a branch/judge node and edge needs a specific branch"
          },
          "target" : {
            "type" : "string",
            "description" : "Downstream node ID (required), must match an existing node.id"
          }
        },
        "required" : [ "source", "target" ],
        "description" : "Edge connection list (required). Each edge.source/edge.target must reference existing node.id"
      }
    },
    "flowDesc" : {
      "type" : "string",
      "description" : "Flow description, maximum 200 characters(required)"
    },
    "flowName" : {
      "type" : "string",
      "description" : "Flow name (required), maximum 80 characters"
    },
    "flowUuid" : {
      "type" : "string",
      "description" : "Draft flow UUID. Use only for update_draft mode. Mutually exclusive with parentFlowUuid"
    },
    "groupId" : {
      "type" : "integer",
      "format" : "int32",
      "description" : "Group ID, default 0"
    },
    "nodeList" : {
      "description" : "Node list (required). It must be non-empty and include exactly one entry node (single_trigger, repeat_trigger, or event_trigger) plus at least one exit_flow node. Each node.id is a request-local identifier used by edge.source/edge.target references, not a persisted database nodeUuid, and it must be unique within this request. Each node.config must be a JSON string whose top-level value is a JSON object that matches node.type. For branch/judge/split nodes, branch IDs referenced by edge.sourceBranchId must be defined inside node.config. Call query_flow_node_config_schema with the target node type before constructing node.config.",
      "type" : "array",
      "items" : {
        "type" : "object",
        "properties" : {
          "config" : {
            "type" : "string",
            "description" : "Node business config as JSON string (required). This field must be a stringified JSON object, not a raw JSON object, array, or plain string. Example: \"{}\" or \"{\\\"key\\\":\\\"value\\\"}\". The schema must match node.type. For judge/push/split nodes, branch IDs used later by edge.sourceBranchId must be declared here first. Build this field from query_flow_node_config_schema for the same node type."
          },
          "desc" : {
            "type" : "string",
            "description" : "Node description (optional). This affects readability only and does not change execution semantics."
          },
          "id" : {
            "type" : "string",
            "description" : "Node ID (required), request-local unique identifier in this canvas, e.g., node_001. This value is referenced by edge.source and edge.target, and is not the persisted database nodeUuid."
          },
          "name" : {
            "type" : "string",
            "description" : "Node display name (required). This affects readability only and does not change execution semantics."
          },
          "type" : {
            "type" : "string",
            "description" : "Node type (required). Supported entry node types are single_trigger, repeat_trigger, and event_trigger; the full canvas must contain exactly one of them. Common node types include feature_judge, event_judge, message_push, wechat_push, webhook_push, time_control, feature_split_flow, event_split_flow, ab_split_flow, and exit_flow."
          }
        },
        "required" : [ "config", "id", "name", "type" ],
        "description" : "Node list (required). It must be non-empty and include exactly one entry node (single_trigger, repeat_trigger, or event_trigger) plus at least one exit_flow node. Each node.id is a request-local identifier used by edge.source/edge.target references, not a persisted database nodeUuid, and it must be unique within this request. Each node.config must be a JSON string whose top-level value is a JSON object that matches node.type. For branch/judge/split nodes, branch IDs referenced by edge.sourceBranchId must be defined inside node.config. Call query_flow_node_config_schema with the target node type before constructing node.config."
      }
    },
    "parentFlowUuid" : {
      "type" : "string",
      "description" : "Base version flow UUID. Use only for new_version mode. Mutually exclusive with flowUuid"
    },
    "projectId" : {
      "type" : "integer",
      "format" : "int32",
      "description" : "Project ID (required)"
    },
    "tzOffset" : {
      "type" : "number",
      "format" : "double",
      "description" : "Timezone offset in hours, default 8.0 (example: 8.0, -5.0)"
    },
    "versionType" : {
      "type" : "integer",
      "format" : "int32",
      "description" : "Version type enum: 1=current version, 2=update content version, 3=new version, 4=test version"
    }
  },
  "required" : [ "edgeList", "flowDesc", "flowName", "nodeList", "projectId" ],
  "additionalProperties" : false
}

